import threading, time
from contextlib import contextmanager
from gateways import FakeClock
import ttl_store_service as svc

class BrokenStore(svc.ThreadSafeTTLStore):
    @contextmanager
    def _lock(self):
        yield

def run_once():
    clock = FakeClock(start=0.0)
    store = BrokenStore(clock=clock, sweep_interval=0.005)
    n_short, n_long = 60, 40
    total = n_short + n_long
    short_keys = [f'short-{i}' for i in range(n_short)]
    long_keys = [f'long-{i}' for i in range(n_long)]
    barrier = threading.Barrier(total)
    errors = []
    lock = threading.Lock()
    def writer(key, ttl):
        try:
            barrier.wait()
            store.put(key, key, ttl=ttl)
            time.sleep(0.001)
        except Exception as exc:
            with lock: errors.append(exc)
    threads = [threading.Thread(target=writer, args=(k,5)) for k in short_keys] + [threading.Thread(target=writer, args=(k,1000)) for k in long_keys]
    store.start_sweeper()
    def wait_until(pred, timeout):
        d=time.monotonic()+timeout
        while time.monotonic()<d:
            if pred(): return
            time.sleep(0.002)
    try:
        for t in threads: t.start()
        for t in threads: t.join()
        if errors: return ('WRITER_ERR', len(errors))
        wait_until(lambda: store.active_count()==total, 2.0)
        clock.advance(10)
        read_results={}
        read_barrier=threading.Barrier(len(short_keys)+len(long_keys))
        def reader(key):
            try:
                read_barrier.wait()
                v=store.get(key)
                with lock: read_results[key]=v
            except Exception as exc:
                with lock: errors.append(exc)
        readers=[threading.Thread(target=reader,args=(k,)) for k in short_keys+long_keys]
        for t in readers: t.start()
        for t in readers: t.join()
        if errors: return ('READER_ERR', len(errors))
        wait_until(lambda: store.active_count()==n_long, 2.0)
    finally:
        store.stop_sweeper()
    ac = store.active_count()
    remaining = set(store._entries.keys())
    return ('FINAL', ac, ac==n_long, remaining==set(long_keys))

# run several trials to see if broken lock ever produces wrong post-state
for i in range(10):
    print(run_once())
