    for n in ast.walk(tree):
        if isinstance(n, ast.ImportFrom):
            for a in n.names: imported.add(a.asname or a.name)
        elif isinstance(n, ast.Import):
            for a in n.names: imported.add((a.asname or a.name).split('.')[0])
